mapper.select:
select ID , operateTime,dept,operator, moduleIdStr as logTypeName, logTypeStr as accessType ,taskName ,digest, moduleId , dataBaseType , appId as dataId from( select id , AREA_ID as areaId ,DEPT as dept,OPERATOR as operator,POLICENO as policeno, APP_ID as appId, MODULE_ID as moduleId, OPERATE_TIME as operateTime, task_name as taskName, IP as ip ,LOG_TYPE as logType,DIGEST as digest ,DATA_BASE_TYPE as dataBaseType, TABLE_NAME_EN as tableNameEn,TABLE_ID as tableId,t2.code_value as moduleIdStr ,t3.code_value as logTypeStr from ( select * from DATAPROCESS
and (upper(OPERATOR) like upper('${searchValue}%') OR upper(TASK_NAME) like upper('${searchValue}%') OR upper(DIGEST) like upper('${searchValue}%') )
) t1 left join DATA_PROCESS_TYPE t2 on upper(t2.code_id) = upper(t1.MODULE_ID) left join DATA_PROCESS_TYPE t3 on upper(t3.code_id) = upper(t1.LOG_TYPE) )
